#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_N 100005
// Define the structure for a tree node
typedef struct Node {
    int value;
    struct Node** children;
    int numChildren;
} Node;
// Function to create a new tree node
Node* createNode(int value) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->value = value;
    node->children = NULL;
    node->numChildren = 0;
    return node;
}
// Function to add a child to a node
void addChild(Node* parent, Node* child) {
    parent->numChildren++;
    parent->children = (Node**)realloc(parent->children, parent->numChildren * sizeof(Node*));
    parent->children[parent->numChildren - 1] = child;
}
// Function to perform DFS on tree 1 and count the number of distinct trees
int countDistinctTrees(Node* tree1, Node* tree2) {
    int count = 0;
    // Perform DFS on tree 1
    void dfsTree1(Node* node) {
        // If the node is a leaf, add the subtree of tree 2 to it
        if (node->numChildren == 0) {
            // Perform DFS on tree 2 and count the number of distinct subtrees
            void dfsTree2(Node* subtree) {
                // If the subtree is not NULL, increment the count
                if (subtree != NULL) {
                    count++;
                }
                // Recursively traverse the children of the subtree
                for (int i = 0; i < subtree->numChildren; i++) {
                    dfsTree2(subtree->children[i]);
                }
            }
            dfsTree2(tree2);
        }
        // Recursively traverse the children of the node
        for (int i = 0; i < node->numChildren; i++) {
            dfsTree1(node->children[i]);
        }
    }
    dfsTree1(tree1);
    return count;
}
int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N1, N2;
        scanf("%d %d", &N1, &N2);
        Node* tree1 = createNode(1);
        Node* tree2 = createNode(1);
        // Read the parents of the nodes in tree 1
        for (int i = 2; i <= N1; i++) {
            int parent;
            scanf("%d", &parent);
            Node* node = createNode(i);
            addChild(tree1, node);
        }
        // Read the parents of the nodes in tree 2
        for (int i = 2; i <= N2; i++) {
            int parent;
            scanf("%d", &parent);
            Node* node = createNode(i);
            addChild(tree2, node);
        }
        // Count the number of distinct trees
        int count = countDistinctTrees(tree1, tree2);
        printf("%d\n", count);
    }
    return 0;
}

